    await openMatchedPairsInventory(mainPage);

    const inventoryFrame = getInventoryFrame(mainPage);
    await expect(inventoryFrame.getByTestId('inventory-form')).toBeVisible({ timeout: 15_000 });

    const dialog = await openCMSOptionsDialog(inventoryFrame);

    // Select PairedPunctuation
    const optionList = dialog.getByRole('listbox', { name: /Option Name/i });
